# Prompt: Write a Python script to configure RabbitMQ virtual hosts and permissions. Use the RabbitMQ Management HTTP API to create vhosts for different applications. Set up users and grant permissions for queue operations. This is for our multi-tenant message broker setup.
# Category: rabbitmq_vhost_isolation

import requests

# RabbitMQ Management API URL
rabbitmq_url = "http://localhost:15672/api"

# Authentication credentials
username = "admin"
password = "password"

# List of virtual hosts and their permissions
vhosts_permissions = [
    {"vhost": "/app1", "users": [{"user": "app1_user", "permissions": {"configure": ".*", "write": ".*", "read": ".*"}}]},
    {"vhost": "/app2", "users": [{"user": "app2_user", "permissions": {"configure": ".*", "write": ".*", "read": ".*"}}]}
]

# Create virtual hosts and set permissions
for vhost in vhosts_permissions:
    # Create virtual host if it doesn't exist
    response = requests.put(f"{rabbitmq_url}/vhosts/{vhost['vhost']}", auth=(username, password))
    if response.status_code == 201 or response.status_code == 409:
        print(f"Vhost {vhost['vhost']} created/already exists")
    
    # Set permissions for each user
    for user in vhost['users']:
        response = requests.put(f"{rabbitmq_url}/permissions/{vhost['vhost']}/{user['user']}", auth=(username, password), json=user['permissions'])
        if response.status_code == 201:
            print(f"Permissions set for {user['user']} on vhost {vhost['vhost']}")

print("Configuration completed.")